/// <summary>
/// Base contract class for processing data response for the KPMG service.
/// </summary>
[DataContract]
public class KPMGCommon_ResponseBase
{
    private KPMGCommon_ResponseStatusCode statusCode;
    private DataAreaId dataAreaId;
    private KPMGCommon_ErrorTxt errorTxt;
    private KPMGCommon_MessageType messageType;

}

Method.Source:
    /// <summary>
/// Get and set the legal entity.
/// </summary>
/// <param name = "_value">The value to set.</param>
/// <returns>Current value of parameter.</returns>
[DataMember('LegalEntity')]
public DataAreaId parmDataAreaId(DataAreaId _value = dataAreaId)
{
    dataAreaId = _value;

    return dataAreaId;
}

/// <summary>
/// Get and set the status code.
