[DataMember('StatusCode')]
public KPMGCommon_ResponseStatusCode parmStatusCode(KPMGCommon_ResponseStatusCode _value = statusCode)
{
    statusCode = _value;

    return statusCode;
}

/// <summary>
/// Get and set the error message.
