[DataMember('MessageType')]
public KPMGCommon_MessageType parmMessageType(KPMGCommon_MessageType _value = messageType)
{
    messageType = _value;

    return messageType;
}

/// <summary>
/// Gets the message type of response.
/// </summary>
/// <returns>The message type</returns>
public KPMGCommon_MessageType getMessageType()
{
    return (new SysDictClass(classIdGet(this)).getAttribute(classStr(DataContractAttribute)) as DataContractAttribute).Name();
}
